import React from 'react';
import '../index.css';

function Home() {
  return (
    <div>
      <h1>Memory Haven</h1>

      <div className="section-box about-box">
        <h2>About</h2>
        <p>Memory Haven allows you to store and time-lock your memories. Whether it's a video, text, or a letter to your future self, keep your moments secure.</p>
      </div>

      <div className="section-box how-it-works-box">
        <h2>How It Works</h2>
        <ul className="how-it-works">
          <li>Sign up and create your account.</li>
          <li>Upload memories as text, images, or videos.</li>
          <li>Set an unlock date for your capsule.</li>
          <li>Revisit your memories when the time comes!</li>
        </ul>
      </div>
    </div>
  );
}

export default Home;
